/**
 * Unit tests for setup-repair hook
 * Tests self-healing: config restore, hook permissions, directories, marker, critical components
 */

import { describe, test, expect, vi, beforeEach, afterAll } from 'vitest';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { mkdtempSync, rmSync, mkdirSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// ---------------------------------------------------------------------------
// Mocks — must be before imports of the module under test
// ---------------------------------------------------------------------------

const FAKE_PLUGIN_ROOT = mkdtempSync(path.join(tmpdir(), 'setup-repair-'));

vi.mock('../../lib/common.js', () => mockCommonBasic({
  getPluginRoot: vi.fn(() => FAKE_PLUGIN_ROOT),
}));

vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: vi.fn((filePath: string, content: string) => {
    // Write for real so downstream reads work
    const dir = path.dirname(filePath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(filePath, content);
  }),
}));

vi.mock('../../lib/agent-teams.js', () => ({
  isAgentTeamsActive: vi.fn(() => false),
}));

import { setupRepair } from '../../setup/setup-repair.js';
import { isAgentTeamsActive } from '../../lib/agent-teams.js';
import { outputWithContext, } from '../../lib/common.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createHookInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: '',
    session_id: 'test-session-repair',
    project_dir: FAKE_PLUGIN_ROOT,
    tool_input: {},
    ...overrides,
  };
}

/** Populate the plugin root with enough files so critical-component checks pass */
function seedPluginRoot() {
  // Create hooks dir with 25 .sh files
  const hooksDir = path.join(FAKE_PLUGIN_ROOT, 'hooks', 'pretool');
  mkdirSync(hooksDir, { recursive: true });
  for (let i = 0; i < 25; i++) {
    writeFileSync(path.join(hooksDir, `hook-${i}.sh`), '#!/bin/bash\n');
  }

  // Create skills dir with 55 SKILL.md files
  for (let i = 0; i < 55; i++) {
    const skillDir = path.join(FAKE_PLUGIN_ROOT, 'skills', `skill-${i}`);
    mkdirSync(skillDir, { recursive: true });
    writeFileSync(path.join(skillDir, 'SKILL.md'), '# Skill\n');
  }

  // Create _lib/common.sh
  const libDir = path.join(FAKE_PLUGIN_ROOT, 'hooks', '_lib');
  mkdirSync(libDir, { recursive: true });
  writeFileSync(path.join(libDir, 'common.sh'), '#!/bin/bash\n');

  // Agents
  const agentsDir = path.join(FAKE_PLUGIN_ROOT, 'agents');
  mkdirSync(agentsDir, { recursive: true });
  writeFileSync(path.join(agentsDir, 'test-agent.md'), '# Agent\n');
}

// ---------------------------------------------------------------------------
// Test suites
// ---------------------------------------------------------------------------

let testCtx: ReturnType<typeof createTestContext>;
beforeEach(() => {
  testCtx = createTestContext({ pluginRoot: FAKE_PLUGIN_ROOT });
  vi.clearAllMocks();
  // Clean the fake plugin root between tests
  rmSync(FAKE_PLUGIN_ROOT, { recursive: true, force: true });
  mkdirSync(FAKE_PLUGIN_ROOT, { recursive: true });
});

afterAll(() => {
  rmSync(FAKE_PLUGIN_ROOT, { recursive: true, force: true });
});

describe('setup-repair', () => {
  // =========================================================================
  // Main export — setupRepair(testCtx)
  // =========================================================================

  describe('setupRepair(testCtx)', () => {
    test('returns silent success when all components are present and healthy', () => {
      // Arrange
      seedPluginRoot();

      // Act
      const result = setupRepair(createHookInput(), testCtx);

      // Assert — no critical failures, should be silent
      expect(result.continue).toBe(true);
    });

    test('creates required directories when missing', () => {
      // Arrange
      seedPluginRoot();

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert — directories should exist after repair
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults'))).toBe(true);
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'context', 'session'))).toBe(true);
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'logs'))).toBe(true);
    });

    test('creates coordination dir when Agent Teams is NOT active', () => {
      // Arrange
      seedPluginRoot();
      vi.mocked(isAgentTeamsActive).mockReturnValue(false);

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'coordination'))).toBe(true);
    });

    test('skips coordination dir when Agent Teams IS active', () => {
      // Arrange
      seedPluginRoot();
      vi.mocked(isAgentTeamsActive).mockReturnValue(true);

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert — coordination dir should NOT be created
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'coordination'))).toBe(false);
    });

    test('regenerates marker file with component counts', () => {
      // Arrange
      seedPluginRoot();

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert
      const markerPath = path.join(FAKE_PLUGIN_ROOT, '.setup-complete');
      expect(fs.existsSync(markerPath)).toBe(true);

      const marker = JSON.parse(fs.readFileSync(markerPath, 'utf-8'));
      expect(marker.version).toBe('4.25.0');
      expect(marker.components.hooks.count).toBeGreaterThanOrEqual(25);
      expect(marker.components.skills.count).toBeGreaterThanOrEqual(55);
      expect(marker.components.agents.count).toBeGreaterThanOrEqual(1);
      expect(marker.repaired_at).toBeDefined();
      expect(marker.environment.os).toBe(process.platform);
    });

    test('restores default config.json when missing', () => {
      // Arrange
      seedPluginRoot();

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert
      const configPath = path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults', 'config.json');
      expect(fs.existsSync(configPath)).toBe(true);

      const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
      expect(config.preset).toBe('complete');
      expect(config.features.skills).toBe(true);
      expect(config.features.hooks).toBe(true);
    });

    test('backs up corrupt config.json and restores default', () => {
      // Arrange
      seedPluginRoot();
      const configDir = path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults');
      mkdirSync(configDir, { recursive: true });
      writeFileSync(path.join(configDir, 'config.json'), '{ invalid json !!!');

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert — corrupt file backed up, fresh one written
      const configPath = path.join(configDir, 'config.json');
      const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
      expect(config.preset).toBe('complete');

      // A .corrupt. backup should exist
      const backups = fs.readdirSync(configDir).filter((f) => f.includes('.corrupt.'));
      expect(backups.length).toBeGreaterThanOrEqual(1);
    });

    test('preserves valid config.json', () => {
      // Arrange
      seedPluginRoot();
      const configDir = path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults');
      mkdirSync(configDir, { recursive: true });
      const customConfig = { preset: 'lite', custom: true };
      writeFileSync(path.join(configDir, 'config.json'), JSON.stringify(customConfig));

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert — custom config preserved, not overwritten
      const config = JSON.parse(fs.readFileSync(path.join(configDir, 'config.json'), 'utf-8'));
      expect(config.preset).toBe('lite');
      expect(config.custom).toBe(true);
    });
  });

  // =========================================================================
  // Critical components check
  // =========================================================================

  // NOTE: setupRepair uses module-level arrays (repairsMade/repairsFailed)
  // that accumulate across calls. The "passes" test must run before the
  // "missing" test to avoid state leakage from repairsFailed.

  describe('critical components check', () => {
    test('passes critical check when enough hooks and skills exist', () => {
      // Arrange
      seedPluginRoot();

      // Act
      const result = setupRepair(createHookInput(), testCtx);

      // Assert — should complete successfully
      expect(result.continue).toBe(true);
    });

    test('notifies user when critical components are missing', () => {
      // Arrange — empty plugin root, no hooks/skills/common.sh

      // Act
      const result = setupRepair(createHookInput(), testCtx);

      // Assert — should notify user about missing critical components
      expect(vi.mocked(outputWithContext)).toHaveBeenCalled();
      expect(result.continue).toBe(true);
    });
  });

  // =========================================================================
  // Hook permissions repair
  // =========================================================================

  describe('hook permissions', () => {
    test('fixes non-executable .sh files', () => {
      // Arrange
      seedPluginRoot();
      // Create a .sh file with mode 0o644 (not executable)
      const nonExecHook = path.join(FAKE_PLUGIN_ROOT, 'hooks', 'pretool', 'non-exec.sh');
      writeFileSync(nonExecHook, '#!/bin/bash\n');
      fs.chmodSync(nonExecHook, 0o644);

      // Act
      setupRepair(createHookInput(), testCtx);

      // Assert — file should now be executable
      const stats = fs.statSync(nonExecHook);
      expect(stats.mode & 0o111).toBeTruthy();
    });
  });
});
